content.text:
// Success response
{
  "jsonrpc": "2.0",
  "id": 1,
  "result": {
    "content": [
      {
        "type": "text",
        "text": "Sunny, 72°F"
      }
    ]
  }
}
// Error response
{
  "jsonrpc": "2.0",
  "id": 1,
  "error": {
    "code": -32000,
    "message": "Invalid location parameter"
  }
}

{
  "initialize request (client -> server)": {
    "jsonrpc": "2.0",
    "id": 1,
    "method": "initialize",
    "params": {
      "protocolVersion": "2024-11-05",
      "clientInfo": { "name": "claude-code", "version": "1.0" },
      "capabilities": { "roots": { "listChanged": true } }
    }
  },

  "initialize response (server -> client)": {
    "jsonrpc": "2.0",
    "id": 1,
    "result": {
      "protocolVersion": "2024-11-05",
      "serverInfo": { "name": "filesystem-mcp", "version": "0.3.1" },
      "capabilities": {
        "tools": {},
        "resources": { "subscribe": false, "listChanged": true }
      }
    }
  },

  "initialized notification (client -> server, no id)": {
    "jsonrpc": "2.0",
    "method": "notifications/initialized"
  },

  "tools/call request": {
    "jsonrpc": "2.0",
    "id": 2,
    "method": "tools/call",
    "params": {
      "name": "read_file",
      "arguments": { "path": "/home/user/project/README.md" }
    }
  },

  "tools/call response (success)": {
    "jsonrpc": "2.0",
    "id": 2,
    "result": {
      "content": [
        {
          "type": "text",
          "text": "# My Project\n\nA Python utility for data processing."
        }
      ],
      "isError": false
    }
  },

  "tools/call response (tool execution failure)": {
    "jsonrpc": "2.0",
    "id": 3,
    "result": {
      "content": [
        {
          "type": "text",
          "text": "Error: File not found at /home/user/project/missing.py"
        }
      ],
      "isError": true
    }
  }
}
